<template>
  <el-form
    ref="form"
    label-width="100px"
  >
    <el-form-item label="公眾帳號ID">
      <el-input
        v-model="form.app_id"
        style="width: 300px"
      /><span class="frm-tips"> 適用於【微信瀏覽器、第三方APP、第三方手機瀏覽器、微信小程序、PC網站】</span>
      <br>
      <span class="frm-tips">微信支付分配的公眾帳號ID（企業號corpid即為此appId）。請到 微信公眾平台 → 開發 → 基本配置 → 獲取</span>
    </el-form-item>
    <el-form-item label="APP應用ID">
      <el-input
        v-model="form.app_app_id"
        style="width: 300px"
      /><span class="frm-tips"> 適用於【第三方APP】</span>
      <br>
      <span
        class="frm-tips"
      >微信開放平台審核通過的應用APPID（請登錄open.weixin.qq.com查看，注意與公眾號的APPID不同）</span>
    </el-form-item>
    <el-form-item label="商戶號">
      <el-input
        v-model="form.merchant_id"
        style="width: 300px"
      /><span class="frm-tips"> 適用於【微信瀏覽器、第三方APP、第三方手機瀏覽器、微信小程序、PC網站】</span><br /><span class="frm-tips">請到 微信支付商戶平台→帳戶中心→商戶訊息→獲取</span>
    </el-form-item>
    <el-form-item label="API密鑰">
      <el-input
        v-model="form.key"
        style="width: 300px"
      /><span class="frm-tips"> 適用於【微信瀏覽器、第三方APP、第三方手機瀏覽器、微信小程序、PC網站】</span><br /><span class="frm-tips">請到 微信支付商戶平台 → 帳戶中心 → API安全 → API密鑰 中設置32位密鑰，並將密鑰複粘貼過來</span>
    </el-form-item>
    <el-form-item label="是否特約商戶">
      <el-switch
        v-model="form.is_servicer"
        active-color="#13ce66"
        inactive-color="#ff4949"
      />
      <span class="frm-tips">如是特約商戶，請聯絡您的服務商獲取如下兩個參數</span>
    </el-form-item>
    <el-form-item label="服務商APPID">
      <el-input
        v-model="form.servicer_app_id"
        style="width: 300px"
      />
    </el-form-item>
    <el-form-item label="服務商商戶號">
      <el-input
        v-model="form.servicer_merchant_id"
        style="width: 300px"
      />
    </el-form-item>
    <el-form-item label="商戶證書">
      <span v-if="form.cert_name"> {{ form.cert_name }}</span>
      <el-upload
        class=""
        action=""
        :on-change="certHandleChange"
        :auto-upload="false"
      >
        <el-button
          size="small"
          type="primary"
        >
          點擊上傳
        </el-button>
      </el-upload>
      <span
        class="frm-tips"
      >微信商戶平台(pay.weixin.qq.com)-->帳戶設置-->API安全-->證書下載 apiclient_cert.pem</span>
    </el-form-item>
    <el-form-item label="商戶證書秘鑰">
      <span v-if="form.cert_key_url"> {{ form.cert_key_name }}</span>
      <el-upload
        class=""
        action=""
        :on-change="keyHandleChange"
        :auto-upload="false"
      >
        <el-button
          size="small"
          type="primary"
        >
          點擊上傳
        </el-button>
      </el-upload>
      <span
        class="frm-tips"
      >微信商戶平台(pay.weixin.qq.com)-->帳戶設置-->API安全-->證書下載 apiclient_key.pem</span>
    </el-form-item>
    <el-form-item label="是否啟用">
      <el-switch
        v-model="form.is_open"
        active-color="#13ce66"
        inactive-color="#ff4949"
      />
    </el-form-item>
    <div class="section-footer with-border content-center">
      <el-button
        v-loading="loading"
        type="primary"
        @click="onSubmit"
      >
        儲存
      </el-button>
    </div>
  </el-form>
</template>
<script>
import { setPaymentSetting, getPaymentSetting } from '../../../../api/trade'
export default {
  data () {
    return {
      activeName: 'wxpay',
      loading: false,
      teegonForm: {
        app_key: '',
        client_secret: '',
        is_open: ''
      },
      form: {
        app_id: '',
        app_app_id: '',
        merchant_id: '',
        key: '',
        is_servicer: false,
        servicer_merchant_id: '',
        servicer_app_id: '',
        cert: '',
        cert_key: '',
        is_open: true
      }
    }
  },
  mounted () {
    this.getConfig()
  },
  methods: {
    handleClick () {
      this.getConfig()
    },
    certHandleChange (file, fileList) {
      this.form.cert = file.raw
    },
    keyHandleChange (file, fileList) {
      this.form.cert_key = file.raw
    },
    getConfig () {
      let query = {}
      if (this.activeName == 'wxpay') {
        query = { pay_type: 'wxpay' }
        getPaymentSetting(query).then((response) => {
          let form =
            Array.isArray(response.data.data) && !response.data.data.length
              ? {}
              : response.data.data
          form.is_servicer = response.data.data.is_servicer == 'true' ? true : false
          form.is_open = response.data.data.is_open == 'true' ? true : false

          for (let key of Object.keys(form)) {
            this.$set(this.form, key, form[key])
          }
          console.log('this.form', this.form)
        })
      } else {
        query = { pay_type: 'teegon' }
        getPaymentSetting(query).then((response) => {
          this.teegonForm = response.data.data
        })
      }
    },
    onSubmit () {
      this.loading = true
      let query = {}
      if (this.activeName == 'wxpay') {
        query = {
          isUploadFile: true,
          pay_type: 'wxpay',
          app_id: this.form.app_id,
          app_app_id: this.form.app_app_id,
          merchant_id: this.form.merchant_id,
          key: this.form.key,
          is_servicer: this.form.is_servicer,
          servicer_merchant_id: this.form.servicer_merchant_id,
          servicer_app_id: this.form.servicer_app_id,
          is_open: this.form.is_open,
          cert: this.form.cert,
          cert_key: this.form.cert_key
        }
      } else {
        query = {
          pay_type: 'teegon',
          config: this.teegonForm
        }
      }
      setPaymentSetting(query)
        .then((response) => {
          this.$message({
            type: 'success',
            message: '儲存成功'
          })
          this.loading = false
        })
        .catch((error) => {
          this.loading = false
        })
    }
  }
}
</script>
