<template>
  <el-form
    ref="form"
    label-width="100px"
  >
    <el-form-item label="合作者PID">
      <el-input
        v-model="form.app_id"
        style="width: 300px"
      />
      <br>
      <span class="frm-tips">APPID</span>
    </el-form-item>
    <el-form-item label="支付寶公鑰">
      <el-input
        v-model="form.ali_public_key"
        type="textarea"
        :rows="5"
        placeholder="請輸入內容"
      />
      <br>
      <span class="frm-tips">RSA2(SHA256)密鑰 支付寶公鑰</span>
    </el-form-item>
    <el-form-item label="應用私鑰">
      <el-input
        v-model="form.private_key"
        type="textarea"
        :rows="5"
        placeholder="請輸入內容"
      />
      <br>
      <span class="frm-tips">RSA2(SHA256)密鑰 自己私鑰</span>
    </el-form-item>
    <el-form-item label="是否啟用">
      <el-switch v-model="form.is_open" />
    </el-form-item>
    <el-form-item label="溫馨提示">
      <span
        class="frm-tips"
      >您綁定的企業支付寶帳號必須開通<a
        href="https://b.alipay.com/signing/productDetail.htm?productId=I1011000290000001001"
        target="_blank"
      >手機網站支付</a></span>
    </el-form-item>
    <div class="section-footer with-border content-center">
      <el-button
        v-loading="loading"
        type="primary"
        @click="onSubmit"
      >
        儲存
      </el-button>
    </div>
  </el-form>
</template>
<script>
import { setPaymentSetting, getPaymentSetting } from '../../../../api/trade'
export default {
  data () {
    return {
      activeName: 'alipay',
      loading: false,
      form: {
        app_id: '',
        key: '',
        is_open: false,
        ali_public_key: '',
        private_key: ''
      }
    }
  },
  mounted () {
    this.getConfig()
  },
  methods: {
    handleClick () {
      this.getConfig()
    },
    getConfig () {
      let query = { pay_type: 'alipay' }
      getPaymentSetting(query).then((response) => {
        this.form = response.data.data
      })
    },
    onSubmit () {
      this.loading = true
      let query = {
        isUploadFile: true,
        pay_type: 'alipay',
        app_id: this.form.app_id,
        private_key: this.form.private_key,
        is_open: this.form.is_open,
        ali_public_key: this.form.ali_public_key
      }
      setPaymentSetting(query)
        .then((response) => {
          this.$message({
            type: 'success',
            message: '儲存成功'
          })
          this.loading = false
        })
        .catch((error) => {
          this.loading = false
        })
    }
  }
}
</script>
